from flask import Flask, request, jsonify
from pymongo import MongoClient
from pymongo.errors import DuplicateKeyError
from bson.objectid import ObjectId
from datetime import datetime

app = Flask(__name__)

# MongoDB Configuration
MONGO_URI = "mongodb://localhost:27017/"
client = MongoClient(MONGO_URI)
db = client.cms_db # Database name

# Collections
users_collection = db.users
documents_collection = db.documents

# Ensure indexes for unique fields and common query fields for better performance
users_collection.create_index("username", unique=True)
users_collection.create_index("email", unique=True)
documents_collection.create_index("author_username")
documents_collection.create_index("tags")
documents_collection.create_index("status")
documents_collection.create_index([("created_at", -1)]) # For sorting by recency

# Helper function for JSON serialization of MongoDB objects
def serialize_doc(doc):
    """Converts MongoDB document objects (like ObjectId and datetime) to strings."""
    if doc:
        doc['_id'] = str(doc['_id'])
        for key, value in doc.items():
            if isinstance(value, datetime):
                doc[key] = value.isoformat()
    return doc

# Error handling helper
def handle_error(message, status_code):
    """Standardized error response."""
    return jsonify({"error": message}), status_code

# --- User Profile Endpoints ---

@app.route('/users', methods=['POST'])
def create_user():
    """
    Creates a new user profile.
    Requires 'username' and 'email' in the request body.
    """
    data = request.json
    username = data.get('username')
    email = data.get('email')

    if not username or not email:
        return handle_error("Username and email are required", 400)

    try:
        user_id = users_collection.insert_one({
            "username": username,
            "email": email,
            "created_at": datetime.utcnow()
        }).inserted_id
    except DuplicateKeyError as e:
        if "username" in str(e):
            return handle_error("User with this username already exists", 409)
        elif "email" in str(e):
            return handle_error("User with this email already exists", 409)
        return handle_error(f"MongoDB error: {str(e)}", 500)

    return jsonify({"message": "User created successfully", "id": str(user_id)}), 201

@app.route('/users', methods=['GET'])
def get_users():
    """Retrieves a list of all user profiles."""
    users = [serialize_doc(user) for user in users_collection.find({})]
    return jsonify(users), 200

@app.route('/users/<username>', methods=['GET'])
def get_user(username):
    """Retrieves a single user profile by username."""
    user = users_collection.find_one({"username": username})
    if not user:
        return handle_error("User not found", 404)
    return jsonify(serialize_doc(user)), 200

@app.route('/users/<username>', methods=['PUT'])
def update_user_profile(username):
    """
    Updates a user's profile information by username.
    Only 'email' is supported for update in this example.
    """
    data = request.json
    new_email = data.get('email')

    if not new_email:
        return handle_error("Email is required for update", 400)

    try:
        result = users_collection.update_one(
            {"username": username},
            {"$set": {"email": new_email, "updated_at": datetime.utcnow()}}
        )
    except DuplicateKeyError as e:
        if "email" in str(e):
            return handle_error("User with this email already exists", 409)
        return handle_error(f"MongoDB error: {str(e)}", 500)

    if result.matched_count == 0:
        return handle_error("User not found", 404)
    if result.modified_count == 0:
        return jsonify({"message": "User email is already the same or no changes made"}), 200

    return jsonify({"message": "User updated successfully"}), 200

@app.route('/users/<username>', methods=['DELETE'])
def delete_user(username):
    """Deletes a user profile by username."""
    result = users_collection.delete_one({"username": username})
    if result.deleted_count == 0:
        return handle_error("User not found", 404)
    return jsonify({"message": "User deleted successfully"}), 200


# --- Document Storage Endpoints ---

@app.route('/documents', methods=['POST'])
def create_document():
    """
    Creates a new document (e.g., article, blog post).
    Requires 'title', 'content', 'author_username' in the request body.
    'tags' (list of strings) and 'status' (draft/published) are optional.
    """
    data = request.json
    title = data.get('title')
    content = data.get('content')
    author_username = data.get('author_username')
    tags = data.get('tags', []) # list of strings
    status = data.get('status', 'draft') # 'draft' or 'published'

    if not title or not content or not author_username:
        return handle_error("Title, content, and author_username are required", 400)

    if not isinstance(tags, list) or not all(isinstance(tag, str) for tag in tags):
        return handle_error("Tags must be a list of strings", 400)

    if not users_collection.find_one({"username": author_username}):
        return handle_error("Author username does not exist", 400)

    if status not in ['draft', 'published']:
        return handle_error("Invalid status. Must be 'draft' or 'published'.", 400)

    document_id = documents_collection.insert_one({
        "title": title,
        "content": content,
        "author_username": author_username,
        "tags": tags,
        "status": status,
        "publish_date": datetime.utcnow() if status == 'published' else None,
        "created_at": datetime.utcnow(),
        "updated_at": datetime.utcnow()
    }).inserted_id

    return jsonify({"message": "Document created successfully", "id": str(document_id)}), 201

@app.route('/documents', methods=['GET'])
def get_documents():
    """
    Retrieves a list of documents.
    Supports filtering by 'status' (draft/published) and 'author'.
    """
    status_filter = request.args.get('status')
    author_filter = request.args.get('author')
    query = {}
    if status_filter in ['draft', 'published']:
        query['status'] = status_filter
    elif status_filter:
        return handle_error("Invalid status parameter. Must be 'draft' or 'published'.", 400)

    if author_filter:
        # Optionally, check if author exists before querying documents
        if not users_collection.find_one({"username": author_filter}):
            return handle_error("Author not found or does not exist", 404)
        query['author_username'] = author_filter

    documents = [serialize_doc(doc) for doc in documents_collection.find(query).sort("created_at", -1)]
    return jsonify(documents), 200

@app.route('/documents/<doc_id>', methods=['GET'])
def get_document(doc_id):
    """Retrieves a single document by its MongoDB ObjectId."""
    try:
        doc = documents_collection.find_one({"_id": ObjectId(doc_id)})
    except Exception: # Catch any BSON related errors for invalid ObjectId format
        return handle_error("Invalid document ID format", 400)

    if not doc:
        return handle_error("Document not found", 404)

    return jsonify(serialize_doc(doc)), 200

@app.route('/documents/<doc_id>', methods=['PUT'])
def update_document(doc_id):
    """
    Updates an existing document by its MongoDB ObjectId.
    Supports updating 'title', 'content', 'tags', and 'status'.
    Automatically sets 'publish_date' if status changes to 'published' and it wasn't already set.
    """
    data = request.json
    update_fields = {}

    if 'title' in data:
        update_fields['title'] = data['title']
    if 'content' in data:
        update_fields['content'] = data['content']
    if 'tags' in data:
        if not isinstance(data['tags'], list) or not all(isinstance(tag, str) for tag in data['tags']):
            return handle_error("Tags must be a list of strings", 400)
        update_fields['tags'] = data['tags']
    if 'status' in data:
        if data['status'] in ['draft', 'published']:
            update_fields['status'] = data['status']
        else:
            return handle_error("Invalid status value. Must be 'draft' or 'published'.", 400)

    if not update_fields:
        return jsonify({"message": "No fields to update"}), 200

    update_fields['updated_at'] = datetime.utcnow()

    # Handle publish_date if status changes to 'published' and it wasn't published before
    if 'status' in update_fields and update_fields['status'] == 'published':
        try:
            current_doc = documents_collection.find_one({"_id": ObjectId(doc_id)}, {"publish_date": 1})
            if current_doc and not current_doc.get('publish_date'):
                update_fields['publish_date'] = datetime.utcnow()
        except Exception:
            return handle_error("Invalid document ID format for status check", 400)

    try:
        result = documents_collection.update_one(
            {"_id": ObjectId(doc_id)},
            {"$set": update_fields}
        )
    except Exception:
        return handle_error("Invalid document ID format", 400)

    if result.matched_count == 0:
        return handle_error("Document not found", 404)
    if result.modified_count == 0:
        return jsonify({"message": "Document is already up to date or no effective changes made"}), 200

    return jsonify({"message": "Document updated successfully"}), 200

@app.route('/documents/<doc_id>', methods=['DELETE'])
def delete_document(doc_id):
    """Deletes a document by its MongoDB ObjectId."""
    try:
        result = documents_collection.delete_one({"_id": ObjectId(doc_id)})
    except Exception:
        return handle_error("Invalid document ID format", 400)

    if result.deleted_count == 0:
        return handle_error("Document not found", 404)
    return jsonify({"message": "Document deleted successfully"}), 200

# --- Document Query Endpoints ---

@app.route('/documents/search', methods=['GET'])
def search_documents():
    """
    Searches for documents based on various criteria.
    Query parameters: 'title' (regex, case-insensitive), 'author', 'tag' (multiple allowed), 'status'.
    """
    query = {}
    title = request.args.get('title')
    author = request.args.get('author')
    tag = request.args.getlist('tag') # Can pass multiple tags like /search?tag=python&tag=flask
    status = request.args.get('status')

    if title:
        query['title'] = {"$regex": title, "$options": "i"} # Case-insensitive regex search
    if author:
        if not users_collection.find_one({"username": author}):
             return handle_error("Author not found or does not exist", 404)
        query['author_username'] = author
    if tag:
        query['tags'] = {"$in": tag} # Documents containing any of the provided tags
    if status in ['draft', 'published']:
        query['status'] = status
    elif status:
        return handle_error("Invalid status parameter. Must be 'draft' or 'published'.", 400)

    documents = [serialize_doc(doc) for doc in documents_collection.find(query).sort("created_at", -1)]
    return jsonify(documents), 200


# --- Aggregation Pipeline Endpoints ---

@app.route('/aggregations/documents_by_author', methods=['GET'])
def documents_by_author():
    """
    Aggregates documents to count how many documents each author has.
    Returns authors sorted by document count (descending).
    """
    pipeline = [
        {"$group": {"_id": "$author_username", "count": {"$sum": 1}}},
        {"$sort": {"count": -1}}
    ]
    results = list(documents_collection.aggregate(pipeline))
    return jsonify(results), 200

@app.route('/aggregations/documents_by_tag', methods=['GET'])
def documents_by_tag():
    """
    Aggregates documents to count how many documents are associated with each tag.
    Returns tags sorted by document count (descending).
    """
    pipeline = [
        {"$unwind": "$tags"}, # Deconstructs the tags array to output a document for each tag
        {"$group": {"_id": "$tags", "count": {"$sum": 1}}},
        {"$sort": {"count": -1}}
    ]
    results = list(documents_collection.aggregate(pipeline))
    return jsonify(results), 200

@app.route('/aggregations/published_documents_count', methods=['GET'])
def published_documents_count():
    """
    Returns the total count of documents that are currently 'published'.
    """
    pipeline = [
        {"$match": {"status": "published"}},
        {"$group": {"_id": None, "count": {"$sum": 1}}} # Group all matching documents into a single document
    ]
    results = list(documents_collection.aggregate(pipeline))
    if results:
        return jsonify({"published_documents_count": results[0]['count']}), 200
    return jsonify({"published_documents_count": 0}), 200

@app.route('/aggregations/recent_documents', methods=['GET'])
def recent_documents():
    """
    Retrieves a specified number of most recently created documents.
    Query parameter: 'limit' (default is 5).
    """
    limit_str = request.args.get('limit', '5')
    try:
        limit = int(limit_str)
        if limit <= 0:
            raise ValueError
    except ValueError:
        return handle_error("Limit must be a positive integer", 400)

    pipeline = [
        {"$sort": {"created_at": -1}},
        {"$limit": limit},
        {"$project": { # Project specific fields and format _id and created_at for output
            "_id": {"$toString": "$_id"},
            "title": 1,
            "author_username": 1,
            "created_at": {"$dateToString": {"format": "%Y-%m-%dT%H:%M:%SZ", "date": "$created_at"}},
            "status": 1
        }}
    ]
    results = list(documents_collection.aggregate(pipeline))
    return jsonify(results), 200

@app.route('/aggregations/top_authors_by_published_documents', methods=['GET'])
def top_authors_by_published_documents():
    """
    Identifies authors with the most published documents.
    Query parameter: 'limit' (default is 3).
    """
    limit_str = request.args.get('limit', '3')
    try:
        limit = int(limit_str)
        if limit <= 0:
            raise ValueError
    except ValueError:
        return handle_error("Limit must be a positive integer", 400)

    pipeline = [
        {"$match": {"status": "published"}}, # Only consider published documents
        {"$group": {"_id": "$author_username", "published_count": {"$sum": 1}}},
        {"$sort": {"published_count": -1}},
        {"$limit": limit}
    ]
    results = list(documents_collection.aggregate(pipeline))
    return jsonify(results), 200


